#include <stdio.h>
#include <string.h>
#include <math.h>
int main(){
	int n,i, count1, count2, Scount, Ncount;
	char c[10] = {118,60,94,62};
	char ch1, ch2;
	scanf("%c %c", &ch1, &ch2);
	scanf("%d", &n);
	for(i = 0;i < 4; i++)
	{
		if(ch1 == c[i])
			count1 = i;
		if(ch2 == c[i])
			count2 = i;
	}

	if(ch1 == ch2||count1-count2 == 2 ||count2 - count1 ==2)
	{
		printf("undefined\n");
		return 0;		
	}
	else if(count1 > count2)
	{
		Scount = count2- count1 + 4;
		Ncount = count1 - count2;
	}
	else
	{
		Scount = count2 - count1;
		Ncount = count1 - count2 + 4;
	}
	int num = n % 4;
	if((Scount != num)&&(Ncount != num)||(Scount == num)&&(Ncount == num))
		printf("undefined\n");
	else if(Scount == num&&Ncount != num)
		printf("cw\n");
	else
		printf("ccw\n");
	return 0;
}

