fn read_line() -> String {
    let mut line = String::new();
    std::io::stdin().read_line(&mut line).expect(
        "Could not read line",
    );
    String::from(&line[..line.len() - 1])
}

macro_rules! read_line {
    (Vec<$t: ty>) => {{
        read_line().split_whitespace().map(|token| {
            <$t as std::str::FromStr>::from_str(token).expect(
                &format!(concat!("Could not parse {} into ", stringify!($t)), token))
        }).collect::<Vec<$t>>()
    }};
    ($($t: ty),*) => {{
        let line = read_line();
        let mut iter = line.split_whitespace();
        let result = ($({
            let token = iter.next().expect("Not enough tokens");
            <$t as std::str::FromStr>::from_str(token).expect(
                &format!(concat!("Could not parse {} into ", stringify!($t)), token))
        }),*);
        if let Some(token) = iter.next() {
            panic!("Unexpected token {}", token);
        }
        result
    }};
}

fn main() {
    let (s, f) = read_line!(String, String);
    let s = s.chars().nth(0).unwrap();
    let f = f.chars().nth(0).unwrap();
    let time = read_line!(usize);
    let all = ['v', '<', '^', '>'];
    let s = all.iter().enumerate().find(|x| *x.1 == s).unwrap().0;
    let f = all.iter().enumerate().find(|x| *x.1 == f).unwrap().0;
    let canCw = (s + time) % 4 == f;
    let canCcw = s == (f + time) % 4;
    println!(
        "{}",
        match (canCw, canCcw) {
            (false, false) => panic!("impossible"),
            (true, false) => "cw",
            (false, true) => "ccw",
            (true, true) => "undefined",
        }
    );
}
